from pathlib import Path
import os

def validate_path(path_str):
 """Validate and analyze a given path."""
 try:
 path = Path(path_str)

 # Check if path exists
 if not path.exists():
 return {"status": "error", "message": "Path does not exist"}

 # Determine path type
 result = {
 "status": "success",
 "absolute": str(path.resolve()),
 "type": "unknown"
 }

 if path.is_file():
 result["type"] = "file"
 result["size"] = path.stat().st_size
 elif path.is_dir():
 result["type"] = "directory"
 result["children"] = len(list(path.iterdir()))
 elif path.is_symlink():
 result["type"] = "symlink"
 result["target"] = str(path.resolve())

 return result

 except PermissionError:
 return {"status": "error", "message": "Permission denied"}
 except OSError as e:
 return {"status": "error", "message": str(e)}

# Usage
print(validate_path("/home/user"))
print(validate_path("nonexistent.txt"))
